```go
package main

import (
	"fmt"
	"time"
)

// ErrTaskFailed is a custom error type that represents a task failure.
type ErrTaskFailed struct {
	// Err is the error associated with the failure.
	Err error
}

// ErrTaskFailed can be used to construct an ErrTaskFailed.
func newErrTaskFailed(err error) ErrTaskFailed {
	return ErrTaskFailed{Err: err}
}

// RunTasks concurrently runs multiple tasks concurrently.
func RunTasks(tasks ...func() error) error {
	start := time.Now()
	for _, task := range tasks {
		result := task()
		if result != nil {
			fmt.Printf("Task %s succeeded with result: %v\n", result, result)
		} else {
			fmt.Printf("Task %s failed with error: %v\n", result, result)
		}
	}
	fmt.Printf("Task execution took %v seconds\n", time.Since(start))
	return nil
}

func main() {
	// Example tasks
	tasks := []func() error{
		// Task 1: Print "Hello World"
		// Result: "Hello World"
		// Err: nil

		// Task 2: Print "Goodbye World"
		// Result: "Goodbye World"
		// Err: nil

		// Task 3: Print "Hello Again"
		// Result: "Hello Again"
		// Err: nil

		// Task 4: Print "Hello World" with delay
		// Result: "Hello World"
		// Err: "sleeping for 5 seconds"
	}

	// Run the tasks
	err := RunTasks(tasks...)
	if err != nil {
		fmt.Printf("Error: %v\n", err)
	}
}
```

In this example:

- We define a custom error type `ErrTaskFailed` that wraps the error returned by any task.
- The `RunTasks` function takes a slice of tasks to run concurrently and starts them concurrently. It prints the result and the error for each task.
- The `main` function demonstrates how to run multiple tasks concurrently and handle errors accordingly.

